#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int SA, SB, SC;
        scanf("%d %d %d", &SA, &SB, &SC);
        if (SB < SA && SB < SC) {
            printf("Bob\n");
        } else if (SC < SA && SC < SB) {
            printf("Alice\n");
        } else {
            printf("Draw\n");
        }
    }
    return 0;
}

