code.Java:
import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; t++) {
            st = new StringTokenizer(br.readLine());
            int SA = Integer.parseInt(st.nextToken());
            int SB = Integer.parseInt(st.nextToken());
            int SC = Integer.parseInt(st.nextToken());
            if (SB < SA && SB < SC) sb.append("Bob\n");
            else if (SC < SA && SC < SB) sb.append("Alice\n");
            else sb.append("Draw\n");
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        SA = int(next(it)); SB = int(next(it)); SC = int(next(it))
        if SB < SA and SB < SC:
            out.append("Bob")
        elif SC < SA and SC < SB:
            out.append("Alice")
        else:
            out.append("Draw")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

